 96→/// Temporary officium directory for scenario tests.
 97→/// Cleaned up on drop, even on panic.
 98→struct jjtlg_TestOfficium {
 99→    id: String,
100→    dir: PathBuf,
101→}
102→
103→impl jjtlg_TestOfficium {
104→    fn new(label: &str) -> Self {
105→        zjjtlg_ensure_project_root();
106→        let ts = chrono::Local::now().format("%H%M%S%.3f").to_string();
107→        let bare_id = format!("test-{}-{}", label, ts);
108→        let dir = PathBuf::from(".claude/jjm/officia").join(&bare_id);
109→        std::fs::create_dir_all(&dir)
110→            .unwrap_or_else(|e| panic!("create test officium {}: {}", dir.display(), e));
111→        Self {
112→            id: format!("\u{2609}{}", bare_id), // ☉ prefix
113→            dir,
114→        }
115→    }
116→}
117→
118→impl Drop for jjtlg_TestOfficium {
119→    fn drop(&mut self) {
120→        let _ = std::fs::remove_dir_all(&self.dir);
121→    }
122→}
