134→// ============================================================================
135→// Preflight
136→// ============================================================================
137→
138→fn zjjtlg_preflight_ssh(host: &str, user: &str) -> bool {
139→    std::process::Command::new("ssh")
140→        .args(["-o", "ConnectTimeout=5", "-o", "BatchMode=yes"])
141→        .arg(format!("{}@{}", user, host))
142→        .arg("exit 0")
143→        .output()
144→        .map(|o| o.status.success())
145→        .unwrap_or(false)
146→}
147→
148→fn zjjtlg_preflight_happy(p: &jjtlg_FundusProfile) -> Result<(), String> {
149→    if !zjjtlg_preflight_ssh(&p.host, &p.user) {
150→        return Err(format!("SSH to {}@{} failed", p.user, p.host));
151→    }
152→    let ssh_test = |cmd: &str| -> bool {
153→        std::process::Command::new("ssh")
154→            .args(["-o", "ConnectTimeout=5", "-o", "BatchMode=yes"])
155→            .arg(format!("{}@{}", p.user, p.host))
156→            .arg(cmd)
157→            .output()
158→            .map(|o| o.status.success())
159→            .unwrap_or(false)
160→    };
161→    if !ssh_test(&format!("test -d $HOME/{}", p.reldir)) {
162→        return Err(format!("reldir not found: $HOME/{}", p.reldir));
163→    }
164→    if !ssh_test(&format!("test -f $HOME/{}/.buk/burc.env", p.reldir)) {
165→        return Err("BUK not installed: .buk/burc.env missing".to_string());
166→    }
167→    // Dispatch smoke: run a trivial tabtarget through BUD to verify station regime etc.
168→    let smoke = std::process::Command::new("ssh")
169→        .args(["-o", "ConnectTimeout=10", "-o", "BatchMode=yes"])
170→        .arg(format!("{}@{}", p.user, p.host))
171→        .arg(format!("cd $HOME/{} && ./tt/buw-rcr.RenderConfigRegime.sh >/dev/null 2>&1", p.reldir))
172→        .output();
173→    match smoke {
174→        Ok(o) if o.status.success() => Ok(()),
175→        Ok(o) => Err(format!("BUD dispatch smoke failed (exit {}) — check station regime (burs.env)",
176→            o.status.code().unwrap_or(-1))),
177→        Err(e) => Err(format!("BUD dispatch smoke SSH error: {}", e)),
178→    }
179→}
