181→// ============================================================================
182→// Output parsing helpers
183→// ============================================================================
184→
185→/// Parse legatio token from bind output ("Legatio L0 bound to ...").
186→fn zjjtlg_parse_legatio_token(output: &str) -> String {
187→    output.lines()
188→        .find(|l| l.contains("Legatio ") && l.contains(" bound to "))
189→        .and_then(|l| {
190→            let rest = l.split("Legatio ").nth(1)?;
191→            rest.split_whitespace().next()
192→        })
193→        .unwrap_or_else(|| panic!("cannot parse legatio token from:\n{}", output))
194→        .to_string()
195→}
196→
197→/// Parse pensum display from relay output ("Pensum ₱XX%YY active.").
198→fn zjjtlg_parse_pensum_display(output: &str) -> String {
199→    output.lines()
200→        .find(|l| l.contains("Pensum ") && l.contains(" active."))
201→        .and_then(|l| {
202→            let rest = l.split("Pensum ").nth(1)?;
203→            rest.split_whitespace().next()
204→        })
205→        .unwrap_or_else(|| panic!("cannot parse pensum from:\n{}", output))
206→        .to_string()
207→}
208→
209→/// Strip ₱ (U+20B1) prefix from pensum display to get raw token.
210→fn zjjtlg_pensum_raw_token(display: &str) -> &str {
211→    display.trim_start_matches('\u{20B1}')
212→}
