218→/// Bind to a fundus profile and return the legatio token.
219→fn zjjtlg_bind_profile(p: &jjtlg_FundusProfile, officium: &jjtlg_TestOfficium) -> String {
220→    let (code, output) = jjrlg_run_bind(
221→        jjrlg_BindArgs {
222→            host: p.host.clone(),
223→            user: p.user.clone(),
224→            reldir: p.reldir.clone(),
225→        },
226→        &officium.id,
227→    );
228→    assert_eq!(code, 0, "bind failed:\n{}", output);
229→    zjjtlg_parse_legatio_token(&output)
230→}
