236→/// Extract a BURX field value from check output (e.g., "BURX_LABEL:value" → "value").
237→fn zjjtlg_extract_burx_field(output: &str, field: &str) -> String {
238→    let prefix = format!("{}:", field);
239→    output.lines()
240→        .find(|l| l.starts_with(&prefix))
241→        .map(|l| l[prefix.len()..].trim().to_string())
242→        .unwrap_or_else(|| panic!("missing {} in output:\n{}", field, output))
243→}
