270→fn jjtlg_relay_refuses_dirty_tree_impl(p: &jjtlg_FundusProfile) {
271→    let officium = jjtlg_TestOfficium::new("dirty-guard");
272→    let token = zjjtlg_bind_profile(p, &officium);
273→
274→    let _marker = jjtlg_DirtyMarker::create();
275→
276→    let (code, output) = jjrlg_run_relay(
277→        jjrlg_RelayArgs {
278→            legatio: token,
279→            tabtarget: JJTLG_RELAY_TABTARGET.to_string(),
280→            timeout: JJTLG_RELAY_TIMEOUT,
281→            firemark: JJTLG_RELAY_FIREMARK.to_string(),
282→        },
283→        &officium.id,
284→    );
285→    assert_ne!(code, 0, "relay should refuse dirty tree:\n{}", output);
286→    assert!(
287→        output.contains("dirty") && output.contains("relay refused"),
288→        "expected dirty-tree refusal message:\n{}", output
289→    );
290→    // _marker dropped here, cleaning up the dirty file
291→}
