377→fn jjtlg_relay_check_poll_impl(p: &jjtlg_FundusProfile) {
378→    let firemark = JJTLG_RELAY_FIREMARK.to_string();
379→
380→    let officium = jjtlg_TestOfficium::new("relay-poll");
381→    let token = zjjtlg_bind_profile(p, &officium);
382→
383→    let (code, output) = jjrlg_run_relay(
384→        jjrlg_RelayArgs {
385→            legatio: token,
386→            tabtarget: JJTLG_RELAY_TABTARGET.to_string(),
387→            timeout: JJTLG_RELAY_TIMEOUT,
388→            firemark,
389→        },
390→        &officium.id,
391→    );
392→    assert_eq!(code, 0, "relay failed:\n{}", output);
393→    let pensum = zjjtlg_parse_pensum_display(&output);
394→    let raw = zjjtlg_pensum_raw_token(&pensum);
395→
396→    // Poll to completion
397→    let (cc, co) = jjrlg_run_check(
398→        jjrlg_CheckArgs { pensum: pensum.clone(), timeout: JJTLG_CHECK_POLL_TIMEOUT },
399→        &officium.id,
400→    );
401→    assert_eq!(cc, 0, "check failed:\n{}", co);
402→    assert!(co.contains("Report: stopped"), "expected stopped:\n{}", co);
403→    assert!(co.contains("BURX_EXIT_STATUS:"), "missing exit status:\n{}", co);
404→
405→    // BURX_LABEL correlation: pensum token round-trips through BURE_LABEL → BURX_LABEL
406→    let label_line = co.lines()
407→        .find(|l| l.starts_with("BURX_LABEL:"))
408→        .unwrap_or_else(|| panic!("no BURX_LABEL in check output:\n{}", co));
409→    assert!(
410→        label_line.contains(raw),
411→        "BURX_LABEL mismatch: expected '{}' in '{}'\nfull output:\n{}", raw, label_line, co
412→    );
413→
414→    // File list on terminal status
415→    assert!(co.contains("Files:"), "no file list on terminal status:\n{}", co);
416→    assert!(co.contains("burx.env"), "burx.env not in file list:\n{}", co);
417→}
