419→fn jjtlg_relay_parallel_impl(p: &jjtlg_FundusProfile) {
420→    let firemark = JJTLG_RELAY_FIREMARK.to_string();
421→
422→    let officium = jjtlg_TestOfficium::new("relay-par");
423→    let token = zjjtlg_bind_profile(p, &officium);
424→
425→    // Dispatch 3 concurrent jobs
426→    let mut pensa = Vec::new();
427→    for i in 0..3 {
428→        let (code, output) = jjrlg_run_relay(
429→            jjrlg_RelayArgs {
430→                legatio: token.clone(),
431→                tabtarget: JJTLG_RELAY_TABTARGET.to_string(),
432→                timeout: JJTLG_RELAY_TIMEOUT,
433→                firemark: firemark.clone(),
434→            },
435→            &officium.id,
436→        );
437→        assert_eq!(code, 0, "relay {} failed:\n{}", i, output);
438→        pensa.push(zjjtlg_parse_pensum_display(&output));
439→    }
440→
441→    // Verify all 3 complete independently with distinct labels
442→    let mut labels = Vec::new();
443→    for (i, pensum) in pensa.iter().enumerate() {
444→        let (cc, co) = jjrlg_run_check(
445→            jjrlg_CheckArgs { pensum: pensum.clone(), timeout: JJTLG_CHECK_POLL_TIMEOUT },
446→            &officium.id,
447→        );
448→        assert_eq!(cc, 0, "check {} failed:\n{}", i, co);
449→        assert!(co.contains("Report: stopped"), "pensum {} not stopped:\n{}", i, co);
450→
451→        if let Some(line) = co.lines().find(|l| l.starts_with("BURX_LABEL:")) {
452→            labels.push(line.to_string());
453→        }
454→    }
455→
456→    // No cross-contamination: all labels must be distinct
457→    for i in 0..labels.len() {
458→        for j in (i + 1)..labels.len() {
459→            assert_ne!(
460→                labels[i], labels[j],
461→                "cross-contamination: pensa {} and {} share label", i, j
462→            );
463→        }
464→    }
465→}
