467→fn jjtlg_relay_concurrent_overlap_impl(p: &jjtlg_FundusProfile) {
468→    let firemark = JJTLG_RELAY_FIREMARK.to_string();
469→
470→    let officium = jjtlg_TestOfficium::new("relay-conc");
471→    let token = zjjtlg_bind_profile(p, &officium);
472→
473→    // Dispatch 3 concurrent relay jobs using the delay tabtarget
474→    let mut pensa = Vec::new();
475→    for i in 0..3 {
476→        let (code, output) = jjrlg_run_relay(
477→            jjrlg_RelayArgs {
478→                legatio: token.clone(),
479→                tabtarget: JJTLG_DELAY_TABTARGET.to_string(),
480→                timeout: JJTLG_RELAY_TIMEOUT,
481→                firemark: firemark.clone(),
482→            },
483→            &officium.id,
484→        );
485→        assert_eq!(code, 0, "relay {} failed:\n{}", i, output);
486→        pensa.push(zjjtlg_parse_pensum_display(&output));
487→    }
488→
489→    // Instant-probe all 3 — 20s sleep guarantees temporal overlap
490→    for (i, pensum) in pensa.iter().enumerate() {
491→        let (cc, co) = jjrlg_run_check(
492→            jjrlg_CheckArgs { pensum: pensum.clone(), timeout: 0 },
493→            &officium.id,
494→        );
495→        assert_eq!(cc, 0, "instant check {} failed:\n{}", i, co);
496→        assert!(
497→            co.contains("Report: running"),
498→            "pensum {} not running (20s sleep should guarantee overlap):\n{}", i, co
499→        );
500→    }
501→
502→    // Poll all 3 to completion, collecting labels and temp dirs
503→    let mut labels = Vec::new();
504→    let mut temp_dirs = Vec::new();
505→    for (i, pensum) in pensa.iter().enumerate() {
506→        let (cc, co) = jjrlg_run_check(
507→            jjrlg_CheckArgs { pensum: pensum.clone(), timeout: JJTLG_DELAY_CHECK_TIMEOUT },
508→            &officium.id,
509→        );
510→        assert_eq!(cc, 0, "poll check {} failed:\n{}", i, co);
511→        assert!(co.contains("Report: stopped"), "pensum {} not stopped:\n{}", i, co);
512→
513→        // Verify BURX_LABEL correlates with pensum token
514→        let raw = zjjtlg_pensum_raw_token(pensum);
515→        let label = zjjtlg_extract_burx_field(&co, "BURX_LABEL");
516→        assert!(
517→            label.contains(raw),
518→            "pensum {} BURX_LABEL mismatch: expected '{}' in '{}'", i, raw, label
519→        );
520→
521→        labels.push(label);
522→        temp_dirs.push(zjjtlg_extract_burx_field(&co, "BURX_TEMP_DIR"));
523→    }
524→
525→    // No cross-contamination: all labels must be distinct
526→    for i in 0..labels.len() {
527→        for j in (i + 1)..labels.len() {
528→            assert_ne!(
529→                labels[i], labels[j],
530→                "cross-contamination: pensa {} and {} share BURX_LABEL", i, j
531→            );
532→        }
533→    }
534→
535→    // Isolation: all temp dirs must be distinct
536→    for i in 0..temp_dirs.len() {
537→        for j in (i + 1)..temp_dirs.len() {
538→            assert_ne!(
539→                temp_dirs[i], temp_dirs[j],
540→                "isolation failure: pensa {} and {} share BURX_TEMP_DIR", i, j
541→            );
542→        }
543→    }
544→}
